import numpy as np

def _normalize(embeds: np.ndarray) -> np.ndarray:
    norms = np.linalg.norm(embeds, axis=1, keepdims=True)
    return embeds / (norms + 1e-10)

def maxsim_score(query_embeds: np.ndarray, doc_embeds: np.ndarray) -> float:
    q_norm = _normalize(query_embeds)   # (q_len, d)
    d_norm = _normalize(doc_embeds)     # (doc_len, d)
    # Cosine similarity matrix: (q_len, doc_len)
    sim_matrix = q_norm @ d_norm.T
    # For each query token, take max over doc tokens
    max_sims = sim_matrix.max(axis=1)   # (q_len,)
    return float(max_sims.sum())

def batch_maxsim(query_embeds: np.ndarray, doc_embeds_list: list) -> np.ndarray:
    scores = np.array([maxsim_score(query_embeds, doc_e) for doc_e in doc_embeds_list])
    return scores
